function solve(n: number): string {
    function convertToBase(number: number, base: number): string {
        const digits = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ";
        let result = "";
        while (number > 0) {
            const remainder = number % base;
            result = digits[remainder] + result;
            number = Math.floor(number / base);
        }
        return result || "0";
    }

    const nSquared = n * n;
    const nCubed = n * n * n;

    const hexResult = convertToBase(nSquared, 16);
    const base36Result = convertToBase(nCubed, 36);

    return hexResult + base36Result;
}
